public static long solve(long[][] points) {
    final long MOD = 10_0000_0007L;
    int n = points.length;
    if (n < 4) return 0;

    // Count the number of points for each y-coordinate
    java.util.HashMap<Long, Integer> yCount = new java.util.HashMap<>();
    for (long[] p : points) {
        yCount.put(p[1], yCount.getOrDefault(p[1], 0) + 1);
    }

    // Sort points by x-coordinate, then y-coordinate
    java.util.Arrays.sort(points, (a, b) -> {
        if (a[0] != b[0]) return Long.compare(a[0], b[0]);
        return Long.compare(a[1], b[1]);
    });

    long result = 0;

    // For each y-coordinate, process pairs of points on that line
    for (int i = 0; i < n; i++) {
        long y1 = points[i][1];
        int count1 = yCount.get(y1);
        if (count1 < 2) continue;

        for (int j = i + 1; j < n; j++) {
            long y2 = points[j][1];
            if (y1 == y2) continue;

            int count2 = yCount.get(y2);
            if (count2 < 1) continue;

            // Calculate the number of ways to choose 2 points from the first line
            long ways1 = (long) (count1 - 1) * count1 / 2;
            // Calculate the number of ways to choose 1 point from the second line
            long ways2 = (long) count2;

            // Total ways for this pair of lines
            long totalWays = ways1 * ways2;

            // Add to result
            result = (result + totalWays) % MOD;
        }
    }

    return result;
}
