    }

    long result = 0;

    for (java.util.Map.Entry<Long, Integer> entry : yCount.entrySet()) {
        long y = entry.getKey();
        int count = entry.getValue();
        if (count < 2) continue;

        long[] otherCounts = new long[yCount.size()];
        int idx = 0;
        for (java.util.Map.Entry<Long, Integer> otherEntry : yCount.entrySet()) {
            if (otherEntry.getKey() != y) {
                otherCounts[idx++] = otherEntry.getValue();
            }
        }

        for (int i = 0; i < count; i++) {
            for (int j = i + 1; j < count; j++) {
                long c = count - 2;
                for (int k = 0; k < idx; k++) {
                    result += c * otherCounts[k];
                    result %= MOD;
                }
            }
        }
    }

    return result;
}
